33	template<typename T>
34	void multi_gpu_gpt_interactive_example(const INIReader reader, std::string in_csv, std::string in_csv_final);
35	void writeOutputIds(const std::string& fName, size_t outCount, size_t total_output_len, int* d_output_ids);
36	
37	int main(int argc, char* argv[])
38	{
39	    mpi::initialize(&argc, &argv);
40	    srand(0);
41	
42	    std::string ini_name;
43	    if (argc >= 2) {
44	        ini_name = std::string(argv[1]);
45	    }
46	    else {
47	        ini_name = "../examples/cpp/multi_gpu_gpt/gpt_config.ini";
48	    }
49	
50	    std::string in_csv;
51	    if (argc >= 3) {
52	        in_csv = std::string(argv[2]);
53	    }
54	    else {
55	        in_csv = "../examples/cpp/multi_gpu_gpt/start_ids.csv";
56	    }
57	
58	    std::string in_csv_final;
59	    if (argc >= 4) {
60	        in_csv_final = std::string(argv[3]);
61	    }
62	    else {
63	        in_csv_final = "../examples/cpp/multi_gpu_gpt/interactive_inputs_ids.csv";
64	    }
65	
66	    INIReader reader = INIReader(ini_name);
67	    if (reader.ParseError() < 0) {
68	        std::cout << "[ERROR] Can't load '" << ini_name << "'\n";
69	        return -1;
70	    }
71	    const std::string data_type = reader.Get("ft_instance_hyperparameter", "data_type");
72	
73	    if (data_type == "fp32") {
74	        multi_gpu_gpt_interactive_example<float>(reader, in_csv, in_csv_final);
75	    }
76	    else if (data_type == "fp16") {
77	        multi_gpu_gpt_interactive_example<half>(reader, in_csv, in_csv_final);
78	    }
79	#ifdef ENABLE_BF16
80	    else if (data_type == "bf16") {
81	        multi_gpu_gpt_interactive_example<__nv_bfloat16>(reader, in_csv, in_csv_final);
82	    }
83	#endif
84	    else {
85	        printf("[ERROR] data_type should be fp32, fp16 or bf16 ! \n");
86	        return -1;
87	    }
88	    mpi::finalize();
89	    return 0;
90	}
91	
92	template<typename T>
93	void multi_gpu_gpt_interactive_example(const INIReader reader, std::string in_csv, std::string in_csv_final)
94	{
95	    const std::string model_name         = reader.Get("ft_instance_hyperparameter", "model_name");
96	    const size_t      max_batch_size     = (size_t)reader.GetInteger("ft_instance_hyperparameter", "max_batch_size");
97	    const size_t      beam_width         = (size_t)reader.GetInteger("ft_instance_hyperparameter", "beam_width");
98	    const uint        top_k              = (uint)reader.GetInteger("ft_instance_hyperparameter", "top_k");
99	    const float       top_p              = reader.GetFloat("ft_instance_hyperparameter", "top_p");
100	    const float       temperature        = reader.GetFloat("ft_instance_hyperparameter", "temperature");
101	    const float       repetition_penalty = reader.GetFloat("ft_instance_hyperparameter", "repetition_penalty", 1.0f);
102	    const float       presence_penalty   = reader.GetFloat("ft_instance_hyperparameter", "presence_penalty", 0.0f);
103	    const std::string model_dir          = std::string(reader.Get("ft_instance_hyperparameter", "model_dir"));
104	    const bool        sparse             = static_cast<bool>(reader.GetInteger("ft_instance_hyperparameter", "sparse"));
105	    const int         int8_mode          = reader.GetInteger("ft_instance_hyperparameter", "int8_mode");
106	    const float       len_penalty        = reader.GetFloat("ft_instance_hyperparameter", "len_penalty");
107	    const float       beam_search_diversity_rate =
108	        reader.GetFloat("ft_instance_hyperparameter", "beam_search_diversity_rate");
109	    const int   min_length            = reader.GetInteger("ft_instance_hyperparameter", "min_length", 0);
110	    const float shared_contexts_ratio = reader.GetFloat("ft_instance_hyperparameter", "shared_contexts_ratio", true);
111	
112	    const int tensor_para_size   = reader.GetInteger("ft_instance_hyperparameter", "tensor_para_size");
113	    const int pipeline_para_size = reader.GetInteger("ft_instance_hyperparameter", "pipeline_para_size");
114	
115	    const size_t head_num       = (size_t)reader.GetInteger(model_name, "head_num");
116	    const size_t size_per_head  = (size_t)reader.GetInteger(model_name, "size_per_head");
117	    const size_t vocab_size     = (size_t)reader.GetInteger(model_name, "vocab_size");
118	    const size_t decoder_layers = (size_t)reader.GetInteger(model_name, "decoder_layers");
119	    const size_t hidden_units   = head_num * size_per_head;
120	    const size_t inter_size     = 4 * hidden_units;
121	
122	    const size_t request_batch_size = reader.GetInteger("request", "request_batch_size");
123	    // The length of tokens we hope this model to generate
124	    const int  request_output_len  = reader.GetInteger("request", "request_output_len");
125	    const bool is_return_log_probs = reader.GetBoolean("request", "return_log_probs", false);
126	    // Whether to include input contexts in computing the cumulative log probabilities.
127	    const bool is_return_context_cum_log_probs = reader.GetBoolean("request", "context_log_probs", false);
128	    if (is_return_log_probs && !is_return_context_cum_log_probs) {
129	        FT_LOG_WARNING("context_log_probs will be ignored since return_log_probs is disabled.");
130	    }
131	    const bool remove_padding = reader.GetBoolean("request", "remove_padding", false);
132	
133	    const int start_id = 50256;
134	    const int end_id   = 50256;
135	
136	    FT_CHECK(head_num % tensor_para_size == 0);
137	    FT_CHECK(decoder_layers % pipeline_para_size == 0);
138	
139	    // GPT Variants parameters: e.g. OPT or BLOOM.
140	    const std::string model_variant = std::string(reader.Get(model_name, "model_variant", "gpt"));
141	
142	    gptVariantParams gpt_variant_params = {};  // default is gpt
143	    if (model_variant == "opt-pre") {
144	        gpt_variant_params.layernorm_eps              = 1e-5f;
145	        gpt_variant_params.layernorm_type             = LayerNormType::pre_layernorm;
146	        gpt_variant_params.activation_type            = ActivationType::Relu;
147	        gpt_variant_params.has_post_decoder_layernorm = true;
148	    }
149	    else if (model_variant == "opt-post") {
150	        gpt_variant_params.layernorm_eps              = 1e-5f;
151	        gpt_variant_params.layernorm_type             = LayerNormType::post_layernorm;
152	        gpt_variant_params.activation_type            = ActivationType::Relu;
153	        gpt_variant_params.has_post_decoder_layernorm = false;
154	    }
155	    else if (model_variant == "bloom-pre") {
156	        gpt_variant_params.layernorm_eps              = 1e-5f;
157	        gpt_variant_params.layernorm_type             = LayerNormType::pre_layernorm;
158	        gpt_variant_params.activation_type            = ActivationType::Gelu;
159	        gpt_variant_params.has_positional_encoding    = false;
160	        gpt_variant_params.has_pre_decoder_layernorm  = true;
161	        gpt_variant_params.has_post_decoder_layernorm = true;
162	        gpt_variant_params.use_attention_linear_bias  = true;
163	    }
164	    else if (model_variant == "bloom-post") {
165	        gpt_variant_params.layernorm_eps              = 1e-5f;
166	        gpt_variant_params.layernorm_type             = LayerNormType::post_layernorm;
167	        gpt_variant_params.activation_type            = ActivationType::Gelu;
168	        gpt_variant_params.has_positional_encoding    = false;
169	        gpt_variant_params.has_pre_decoder_layernorm  = true;
170	        gpt_variant_params.has_post_decoder_layernorm = true;
171	        gpt_variant_params.use_attention_linear_bias  = true;
172	    }
173	    gpt_variant_params.has_adapters       = reader.GetBoolean(model_name, "has_adapters", false);
174	    gpt_variant_params.adapter_inter_size = reader.GetInteger(model_name, "adapter_inter_size", inter_size);
175	    gpt_variant_params.layernorm_eps = reader.GetFloat(model_name, "layernorm_eps", gpt_variant_params.layernorm_eps);
176	
177	    // Prepare the parallelism parameters
178	    int rank       = mpi::getCommWorldRank();
179	    int world_size = mpi::getCommWorldSize();
180	    if (rank == 0) {
181	        printf("Total ranks: %d.\n", world_size);
182	    }
183	    int device, device_count;
184	    check_cuda_error(cudaGetDeviceCount(&device_count));
185	    check_cuda_error(cudaSetDevice(rank % device_count));
186	    check_cuda_error(cudaGetDevice(&device));
187	
188	    struct cudaDeviceProp prop;
189	    check_cuda_error(cudaGetDeviceProperties(&prop, device));
190	    printf("Device %s\n", prop.name);
191	
192	    printf("P%d is running with %d GPU.\n", rank, device);
193	
194	    if (tensor_para_size * pipeline_para_size != world_size) {
195	        printf("[ERROR] tensor_para_size * pipeline_para_size should equal to world_size \n");
196	        exit(-1);
197	    }
198	
199	    const int layers_per_group = decoder_layers / pipeline_para_size;
200	    if (layers_per_group * pipeline_para_size != (int)decoder_layers) {
201	        printf("[ERROR] layers_per_group (%d) * pipeline_para_size (%d) should equal to decoder_layers (%ld) \n",
202	               layers_per_group,
203	               pipeline_para_size,
204	               decoder_layers);
205	        exit(-1);
206	    }
207	
208	    // assume gpu_num = k * n,
209	    // tensor parallelism group size is n
210	    // pipeline parallelism group size is k
211	
212	    NcclParam tensor_para;
213	    NcclParam pipeline_para;
214	    ftNcclInitialize(tensor_para, pipeline_para, tensor_para_size, pipeline_para_size);
215	
216	    // Read ids of request from file.
217	    size_t           max_input_len = -1;
218	    std::vector<int> v_start_lengths;
219	    std::vector<int> v_start_ids;
220	    read_start_ids(request_batch_size, &v_start_lengths, &v_start_ids, max_input_len, end_id, 1, in_csv);
221	
222	    int* d_input_ids;
223	    int* d_input_lengths;
224	    if (max_input_len == 0) {
225	        // unconditional case, no input ids, so do nothing.
226	        d_input_ids     = nullptr;
227	        d_input_lengths = nullptr;
228	        max_input_len   = 0;
229	    }
230	    else {
231	        // conditional case.
232	        deviceMalloc(&d_input_ids, request_batch_size * max_input_len, false);
233	        deviceMalloc(&d_input_lengths, request_batch_size, false);
234	        cudaH2Dcpy(d_input_ids, v_start_ids.data(), request_batch_size * max_input_len);
235	        cudaH2Dcpy(d_input_lengths, v_start_lengths.data(), request_batch_size);
236	    }
237	
238	    const int first_output_len = max_input_len + request_output_len;
239	    // When a model doesn't have a learnt positional encoding, there is no limit on the sequence length.
240	    // Set by the max sequence length by a reasonably large value unless the config provides the value.
241	    const size_t   max_seq_len = gpt_variant_params.has_positional_encoding ?
242	                                     (size_t)reader.GetInteger("ft_instance_hyperparameter", "max_seq_len") :
243	                                     (size_t)reader.GetInteger("ft_instance_hyperparameter",
244	                                                             "max_seq_len",
245	                                                             max_input_len + 5 * request_output_len);
246	    const uint32_t session_len = (uint32_t)max_seq_len;
247	
248	    size_t           max_input_len_final = -1;
249	    std::vector<int> v_lengths_final;
250	    std::vector<int> v_ids_final;
251	    read_start_ids(request_batch_size, &v_lengths_final, &v_ids_final, max_input_len_final, end_id, 1, in_csv_final);
252	
253	    int* d_input_ids_final;
254	    int* d_input_lengths_final;
255	    if (max_input_len_final == 0) {
256	        // unconditional case, no input ids, so do nothing.
257	        d_input_ids_final     = nullptr;
258	        d_input_lengths_final = nullptr;
259	        max_input_len_final   = 0;
260	    }
261	    else {
262	        // conditional case.
263	        deviceMalloc(&d_input_ids_final, request_batch_size * max_input_len_final, false);
264	        deviceMalloc(&d_input_lengths_final, request_batch_size, false);
265	        cudaH2Dcpy(d_input_ids_final, v_ids_final.data(), request_batch_size * max_input_len_final);
266	        cudaH2Dcpy(d_input_lengths_final, v_lengths_final.data(), request_batch_size);
267	    }
268	    const size_t total_output_len = first_output_len + max_input_len_final + request_output_len;
269	    if (total_output_len > (int)max_seq_len) {
270	        FT_LOG_ERROR("first_output_len (%d) should be <= max_seq_len (%lu). \n", first_output_len, max_seq_len);
271	        exit(-1);
272	    }
273	    if (total_output_len > (int)session_len) {
274	        FT_LOG_ERROR("first_output_len (%d) should be <= session_len (%u). \n", first_output_len, session_len);
275	        exit(-1);
276	    }
277	
278	    cudaStream_t     stream;
279	    cublasHandle_t   cublas_handle;
280	    cublasLtHandle_t cublaslt_handle;
281	    cudaStreamCreate(&stream);
282	    cublasCreate(&cublas_handle);
283	    cublasLtCreate(&cublaslt_handle);
284	    cublasSetStream(cublas_handle, stream);
285	#ifdef SPARSITY_ENABLED
286	    cusparseLtHandle_t cusparselt_handle;
287	    CHECK_CUSPARSE(cusparseLtInit(&cusparselt_handle));
288	    cublasAlgoMap* cublas_algo_map = new cublasAlgoMap(GEMM_CONFIG, SPGEMM_CONFIG);
289	#else
290	    cublasAlgoMap*  cublas_algo_map = new cublasAlgoMap(GEMM_CONFIG);
291	#endif
292	
293	    Allocator<AllocatorType::CUDA> allocator(getDevice());
294	
295	    std::mutex* cublas_wrapper_mutex = new std::mutex();
296	#ifdef SPARSITY_ENABLED
297	    cublasMMWrapper cublas_wrapper = cublasMMWrapper(
298	        cublas_handle, cublaslt_handle, cusparselt_handle, stream, cublas_algo_map, cublas_wrapper_mutex, &allocator);
299	#else
300	    cublasMMWrapper cublas_wrapper =
301	        cublasMMWrapper(cublas_handle, cublaslt_handle, stream, cublas_algo_map, cublas_wrapper_mutex, &allocator);
302	#endif
303	
304	    if (std::is_same<T, half>::value) {
305	        cublas_wrapper.setGemmConfig(CUDA_R_16F, CUDA_R_16F, CUDA_R_16F, CUDA_R_32F);
306	    }
307	#ifdef ENABLE_BF16
308	    else if (std::is_same<T, __nv_bfloat16>::value) {
309	        cublas_wrapper.setBF16GemmConfig();
310	    }
311	#endif
312	    else if (std::is_same<T, float>::value) {
313	        cublas_wrapper.setFP32GemmConfig();
314	    }
315	
316	    // Prompt Learning Configurations
317	    int                prompt_learning_start_id = reader.GetInteger(model_name, "prompt_learning_start_id", end_id + 1);
318	    PromptLearningType prompt_learning_type =
319	        static_cast<PromptLearningType>(reader.GetInteger(model_name, "prompt_learning_type", 0));
320	
321	    // NOTE：specify task names, take name id, prompt length in order to load those prompt learning tables.
322	    // for example:
323	    // std::map<std::string, std::pair<int, int>> p_prompt_tuning_table_pair_{{"sentiment", {0, 10}},
324	    //                                                                        {"intent_and_slot", {1, 10}},
325	    //                                                                        {"squad", {2, 16}}};
326	
327	    std::map<std::string, std::pair<int, int>> p_prompt_tuning_table_pair_;
328	
329	    // NOTE: get prompt table pairs from configuration files
330	    const int num_tasks = reader.GetInteger(model_name, "num_tasks", 0);
331	    for (int task_name_id = 0; task_name_id < num_tasks; task_name_id++) {
332	        std::string config_task_name = model_name + "_task_" + std::to_string(task_name_id);
333	        std::string task_name        = reader.Get(config_task_name, "task_name");
334	        const int   prompt_length    = reader.GetInteger(config_task_name, "prompt_length", 0);
335	        p_prompt_tuning_table_pair_.insert({task_name, {task_name_id, prompt_length}});
336	    }
337	
338	    // NOTE: task_name_ids for each sequence in one batch
339	    // Each sequence can have different prompt learning task ids
340	    std::vector<int> p_prompt_tuning_task_name_ids(request_batch_size, 0);
341	
342	    ParallelGptWeight<T> gpt_weights(hidden_units,
343	                                     inter_size,
344	                                     vocab_size,
345	                                     decoder_layers,
346	                                     max_seq_len,
347	                                     tensor_para.world_size_,
348	                                     tensor_para.rank_,
349	                                     pipeline_para.world_size_,
350	                                     pipeline_para.rank_,
351	                                     int8_mode,
352	                                     prompt_learning_type,
353	                                     p_prompt_tuning_table_pair_,
354	                                     gpt_variant_params);
355	    gpt_weights.loadModel(model_dir);
356	#ifdef SPARSITY_ENABLED
357	    if (sparse) {
358	        printf("[INFO] Compress weights for sparse inference\n");
359	        gpt_weights.compress_weights(cublas_wrapper);
360	    }
361	#endif
362	
363	    unsigned long long random_seed;
364	    if (rank == 0) {
365	        random_seed = (unsigned long long)(0);
366	    }
367	    if (world_size > 1) {
368	        mpi::bcast(&random_seed, 1, mpi::MPI_TYPE_UNSIGNED_LONG_LONG, 0, mpi::COMM_WORLD);
369	    }
370	
371	    AttentionType attention_type = getAttentionType<T>(size_per_head,
372	                                                       getSMVersion(),
373	                                                       remove_padding,  // remove_padding
374	                                                       0,               // gpt supports any-seq-length fmha
375	                                                       true,            // is_fuse
376	                                                       false,           // with_relative_position_bias
377	                                                       true);           // causal_mask
378	
379	    ParallelGpt<T> gpt = ParallelGpt<T>(0,  // max_batch_size, FT will adjust the buffer automatically.
380	                                        0,  // max_seq_len, FT will adjust the buffer automatically.
381	                                        0,  // max_input_len, FT will adjust the buffer automatically.
382	                                        beam_width,
383	                                        head_num,
384	                                        size_per_head,
385	                                        inter_size,
386	                                        decoder_layers,
387	                                        0,   // expert_num
388	                                        0,   // moe_k
389	                                        {},  // moe_layer_index
390	                                        vocab_size,
391	                                        start_id,
392	                                        end_id,
393	                                        prompt_learning_start_id,  // p/prompt tuning virtual token start id
394	                                        prompt_learning_type,
395	                                        gpt_variant_params,
396	                                        0.0f,  // beam_search_diversity_rate,
397	                                        0,     // top_k,
398	                                        0.0,   // top_p,
399	                                        0,     // random_seed,
400	                                        1.0f,  // temperature,
401	                                        0.0f,  // len_penalty,
402	                                        1.0f,  // repetition_penalty,
403	                                        tensor_para,
404	                                        pipeline_para,
405	                                        stream,
406	                                        &cublas_wrapper,
407	                                        &allocator,
408	                                        false,
409	                                        &prop,
410	                                        attention_type,
411	                                        sparse,
412	                                        int8_mode,
413	                                        nullptr,
414	                                        0);
415	    /* shared_contexts_ratio); */
416	
417	    int* d_output_ids;
418	    int* d_sequence_lengths;
419	    deviceMalloc(&d_output_ids, request_batch_size * beam_width * first_output_len, false);
420	    deviceMalloc(&d_sequence_lengths, request_batch_size * beam_width, false);
421	    std::vector<uint32_t> output_seq_len(request_batch_size, first_output_len);
422	
423	    std::unordered_map<std::string, Tensor> input_tensors = std::unordered_map<std::string, Tensor>{
424	        {"input_ids",
425	         Tensor{MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size, (size_t)max_input_len}, d_input_ids}},
426	        {"input_lengths", Tensor{MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size}, d_input_lengths}},
427	        {"output_seq_len",
428	         Tensor{MEMORY_CPU, TYPE_UINT32, std::vector<size_t>{request_batch_size}, output_seq_len.data()}}};
429	    if (top_k == 0 && top_p == 0.0f) {
430	        FT_CHECK(beam_width > 1);
431	        input_tensors.insert({"beam_search_diversity_rate",
432	                              Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &beam_search_diversity_rate}});
433	    }
434	    else {
435	        if (top_p != 0.0f) {
436	            input_tensors.insert({"runtime_top_p", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &top_p}});
437	        }
438	        if (top_k != 0) {
439	            input_tensors.insert({"runtime_top_k", Tensor{MEMORY_CPU, TYPE_UINT32, std::vector<size_t>{1}, &top_k}});
440	        }
441	    }
442	    if (num_tasks > 0) {
443	        input_tensors.insert({"prompt_learning_task_name_ids",
444	                              Tensor{MEMORY_CPU,
445	                                     TYPE_INT32,
446	                                     std::vector<size_t>{request_batch_size},
447	                                     p_prompt_tuning_task_name_ids.data()}});
448	    }
449	    input_tensors.insert({"session_len", Tensor{MEMORY_CPU, TYPE_UINT32, std::vector<size_t>{1}, &session_len}});
450	    input_tensors.insert({"temperature", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &temperature}});
451	    input_tensors.insert({"len_penalty", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &len_penalty}});
452	    if (repetition_penalty != 1.0f) {
453	        input_tensors.insert({"repetition_penalty", {MEMORY_CPU, TYPE_FP32, {1}, &repetition_penalty}});
454	    }
455	    if (presence_penalty != 0.0f) {
456	        input_tensors.insert({"presence_penalty", {MEMORY_CPU, TYPE_FP32, {1}, &presence_penalty}});
457	    }
458	    input_tensors.insert({"min_length", Tensor{MEMORY_CPU, TYPE_INT32, std::vector<size_t>{1}, &min_length}});
459	    input_tensors.insert({"random_seed", Tensor{MEMORY_CPU, TYPE_UINT64, std::vector<size_t>{1}, &random_seed}});
460	
461	    std::unordered_map<std::string, Tensor> output_tensors = std::unordered_map<std::string, Tensor>{
462	        {"output_ids",
463	         Tensor{MEMORY_GPU,
464	                TYPE_INT32,
465	                std::vector<size_t>{request_batch_size, beam_width, (size_t)first_output_len},
466	                d_output_ids}},
467	        {"sequence_length",
468	         Tensor{MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size, beam_width}, d_sequence_lengths}}};
469	
470	    float* output_log_probs = nullptr;
471	    float* d_cum_log_probs  = nullptr;
472	    if (is_return_log_probs) {
473	        deviceMalloc(&output_log_probs, request_batch_size * beam_width * request_output_len);
474	        output_tensors.insert({"output_log_probs",
475	                               Tensor{MEMORY_GPU,
476	                                      TYPE_FP32,
477	                                      std::vector<size_t>{request_batch_size, beam_width, (size_t)request_output_len},
478	                                      output_log_probs}});
479	        deviceMalloc(&d_cum_log_probs, request_batch_size * beam_width);
480	        output_tensors.insert(
481	            {"cum_log_probs",
482	             Tensor{MEMORY_GPU, TYPE_FP32, std::vector<size_t>{request_batch_size, beam_width}, d_cum_log_probs}});
483	        input_tensors.insert({"is_return_context_cum_log_probs",
484	                              Tensor{MEMORY_CPU, TYPE_BOOL, std::vector<size_t>{1}, &is_return_context_cum_log_probs}});
485	    }
486	
487	    int* d_output_ids_final;
488	    int* d_sequence_lengths_final;
489	    deviceMalloc(&d_output_ids_final, request_batch_size * beam_width * total_output_len, false);
490	    deviceMalloc(&d_sequence_lengths_final, request_batch_size * beam_width, false);
491	    std::vector<uint32_t> output_seq_len_final(request_batch_size, total_output_len);
492	
493	    std::unordered_map<std::string, Tensor> input_tensors_final = input_tensors;
494	    for (auto it = input_tensors_final.begin(); it != input_tensors_final.end();) {
495	        if (it->first == "input_ids" || it->first == "input_lengths" || it->first == "output_seq_len"
496	            || it->first == "session_len") {
497	            it = input_tensors_final.erase(it);
498	        }
499	        else {
500	            it++;
501	        }
502	    }
503	    input_tensors_final.insert(
504	        {"input_ids", {MEMORY_GPU, TYPE_INT32, {request_batch_size, (size_t)max_input_len_final}, d_input_ids_final}});
505	    input_tensors_final.insert(
506	        {"input_lengths", {MEMORY_GPU, TYPE_INT32, {request_batch_size}, d_input_lengths_final}});
507	    input_tensors_final.insert(
508	        {"output_seq_len", {MEMORY_CPU, TYPE_UINT32, {request_batch_size}, output_seq_len_final.data()}});
509	    bool continue_gen = true;
510	    input_tensors_final.insert({"continue_gen", {MEMORY_CPU, TYPE_BOOL, {1}, &continue_gen}});
511	
512	    std::unordered_map<std::string, Tensor> output_tensors_final{
513	        {"output_ids",
514	         {MEMORY_GPU, TYPE_INT32, {request_batch_size, beam_width, total_output_len}, d_output_ids_final}},
515	        {"sequence_length", {MEMORY_GPU, TYPE_INT32, {request_batch_size, beam_width}, d_sequence_lengths_final}}};
516	    float* output_log_probs_final = nullptr;
517	    float* d_cum_log_probs_final  = nullptr;
518	    if (is_return_log_probs) {
519	        deviceMalloc(&output_log_probs_final, request_batch_size * beam_width * request_output_len);
520	        output_tensors_final.insert(
521	            {"output_log_probs",
522	             Tensor{MEMORY_GPU,
523	                    TYPE_FP32,
524	                    std::vector<size_t>{request_batch_size, beam_width, (size_t)request_output_len},
525	                    output_log_probs_final}});
526	        deviceMalloc(&d_cum_log_probs_final, request_batch_size * beam_width);
527	        output_tensors_final.insert(
528	            {"cum_log_probs",
529	             Tensor{
530	                 MEMORY_GPU, TYPE_FP32, std::vector<size_t>{request_batch_size, beam_width}, d_cum_log_probs_final}});
531	    }
532	
533	    print_mem_usage();
534	
535	    int ite = 1;
536	    cudaDeviceSynchronize();
537	    mpi::barrier();
538	
539	    cudaProfilerStart();
540	    // warm up
541	    ite = 1;
542	    ft_nvtx::setScope("warmup_time");
543	    PUSH_RANGE("warmup time")
544	    for (int i = 0; i < ite; ++i) {
545	        gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
546	        gpt.forward(&output_tensors_final, &input_tensors_final, &gpt_weights);
547	    }
548	    cudaDeviceSynchronize();
549	    mpi::barrier();
550	
551	    POP_RANGE;
552	    ft_nvtx::resetScope();
553	
554	    if (rank == 0) {
555	        size_t outCount = first_output_len * request_batch_size * beam_width;
556	        writeOutputIds("out.interm", outCount, first_output_len, d_output_ids);
557	
558	        outCount = total_output_len * request_batch_size * beam_width;
559	        writeOutputIds("out", outCount, total_output_len, d_output_ids_final);
560	
561	        if (d_cum_log_probs != nullptr) {
562	            std::string   logprob_fname = "logprob.out";
563	            std::ofstream logprob_file  = std::ofstream("logprob.out", std::ios::out);
564	            if (!logprob_file.is_open()) {
565	                printf("[WARNING] Cannot write results into output file %s \n", logprob_fname.c_str());
566	            }
567	            else {
568	                size_t cum_log_probs_size = request_batch_size * beam_width;
569	                printf("[INFO] Writing %ld elements (log probs)\n", cum_log_probs_size);
570	                float* h_buf = new float[cum_log_probs_size];
571	                cudaD2Hcpy(h_buf, d_cum_log_probs, cum_log_probs_size);
572	                for (size_t i = 0; i < cum_log_probs_size; i++) {
573	                    logprob_file << h_buf[i] << std::endl;
574	                    if (i < 10) {
575	                        printf(" %10.6f\n", h_buf[i]);
576	                    }
577	                }
578	                delete[] h_buf;
579	            }
580	            logprob_file.close();
581	        }
582	    }
583	
584	    // test time
585	    struct timeval start, end;
586	    mpi::barrier();
587	    cudaDeviceSynchronize();
588	    gettimeofday(&start, NULL);
589	
590	    ite = 10;
591	
592	    ft_nvtx::setScope("total_time");
593	    PUSH_RANGE("total time")
594	    for (int i = 0; i < ite; ++i) {
595	        gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
596	        gpt.forward(&output_tensors_final, &input_tensors_final, &gpt_weights);
597	    }
598	
599	    cudaDeviceSynchronize();
600	    mpi::barrier();
601	
602	    POP_RANGE;
603	    ft_nvtx::resetScope();
604	    gettimeofday(&end, NULL);
605	
606	    cudaProfilerStop();
607	
608	    printf("[INFO] request_batch_size %ld beam_width %ld head_num %ld size_per_head %ld total_output_len %ld"
609	           " decoder_layers %ld vocab_size %ld FT-CPP-decoding-beamsearch-time %.2f ms\n",
610	           request_batch_size,
611	           beam_width,
612	           head_num,
613	           size_per_head,
614	           total_output_len,
615	           decoder_layers,
616	           vocab_size,
617	           ((end.tv_sec - start.tv_sec) * 1000 + (end.tv_usec - start.tv_usec) * 0.001) / ite);
618	
619	    ftNcclParamDestroy(tensor_para);
620	    ftNcclParamDestroy(pipeline_para);
621	
622	#ifdef SPARSITY_ENABLED
623	    cusparseLtDestroy(&cusparselt_handle);
624	#endif
625	    delete cublas_algo_map;
626	    delete cublas_wrapper_mutex;
627	    return;
628	}
629	
630	void writeOutputIds(const std::string& fName, size_t outCount, size_t total_output_len, int* d_output_ids)
631	{
632	    auto outFile = std::ofstream(fName, std::ios::out);
633	    if (!outFile.is_open()) {
634	        printf("[WARNING] Cannot write results into output file %s \n", fName.c_str());
635	    }
636	    else {
637	        int* hBuf = new int[outCount];
638	        cudaD2Hcpy(hBuf, d_output_ids, outCount);
639	
640	        {
641	            std::cout << "Writing " << outCount << " elements\n";
642	            int zeroCount = 0;
643	            for (size_t i = 0; i < outCount; i++) {
644	                if (hBuf[i] == int(0)) {
645	                    zeroCount++;
646	                }
647	                outFile << hBuf[i] << " ";
648	                if ((i + 1) % (total_output_len) == 0) {
649	                    outFile << std::endl;
650	                }
651	
652	                if (i < 10) {
653	                    printf("%5d ", hBuf[i]);
654	                }
655	                if ((i + 1) % (total_output_len) == 0 && i < 10) {
656	                    std::cout << std::endl;
657	                }
658	            }
659	            std::cout << std::endl << "zeroCount = " << zeroCount << std::endl;
660	        }
661	        delete[] hBuf;
662	    }
663	    outFile.close();
664	}
