80	template<typename T>
81	class GptStreamer {
82	
83	protected:
84	    // stremer settings
85	    const int max_batch_size;
86	    const int max_output_length;  // including both input and generated tokens.
87	
88	    // results
89	    int*  output_ids;
90	    int*  sequence_lengths;
91	    bool* finished;
92	
93	    // decoder settings
94	    ParallelGpt<T>*                                gpt_;
95	    std::unordered_map<std::string, Tensor>*       output_tensors_;
96	    const std::unordered_map<std::string, Tensor>* input_tensors_;
97	    const ParallelGptWeight<T>*                    gpt_weights_;
98	
99	    // streamer status and internal buffers
100	    int          prev_step          = 0;
101	    int          curr_step          = 0;
102	    bool         is_generation_done = false;
103	    cudaStream_t stream;
104	
105	    /**
106	     * \brief Stop criteria whether to stop generation
107	     *
108	     * This function determines whether to stop generation. If a user
109	     * wants to stop by a customized criteria, it is enough to override
110	     * this function that updates `finished` and `sequence_lengths`.
111	     *
112	     * \param step_from The generation step where we check from.
113	     * \param step_to The current generation step.
114	     *      The function will check step_from <= step < step_to.
115	     * \param output_ids An integer array pointer of a host in order to copy
116	     *      generated outputs from device.
117	     *
118	     * \return true if all generation have done. Otherwise, false.
119	     */
120	    virtual bool stopCriteria(const int step_from, const int step_to, const int* output_ids)
121	    {
122	        assert(step_from <= step_to);
123	        int batch_size = output_tensors_->at("output_ids").shape[0];
124	        for (int step = step_from; step < step_to; step++) {
125	            bool stop_generation = true;
126	            for (int i = 0; i < batch_size; i++) {
127	                if (!finished[i]) {
128	                    // Let 50256 be the end token id.
129	                    if (output_ids[step * batch_size + i] == END_TOKEN_ID) {
130	                        finished[i] = true;
131	                    }
132	                    else {
133	                        sequence_lengths[i] += 1;
134	                    }
135	                }
136	                if (!finished[i]) {
137	                    stop_generation = false;
138	                }
139	            }
140	            if (stop_generation) {
141	                return true;
142	            }
143	        }
144	        return false;
145	    }
146	
147	    /**
148	     * \brief A hook function that performs during streaming
149	     *
150	     * This function performs a custom logic just after copying generated
151	     * tokens (`output_ids`) to the host.
152	     *
153	     * \param step_from The generation step where the function starts from.
154	     * \param step_to The generation step where the function ends at.
155	     *      The function deals the output_ids step_from <= step < step_to.
156	     * \param output_ids The output ids
157	     */
158	    virtual void streamHook(const int prev_step, const int curr_step, const int* output_ids) {}
159	
160	    /**
161	     * \brief Stream preparation function
162	     *
163	     * This function calls just before streaming inside `streamDecoding`.
164	     * Please override this function to do anything, if a user further needs
165	     * inside an overridden function (`streamHook` or `stopCriteria`), e.g.
166	     * allocating buffers.
167	     */
168	    virtual void onStreamBegin(const int batch_size, const int input_len) {}
169	
170	    /**
171	     * \brief Stream cooling down function
172	     *
173	     * This function calls just after streaming inside `streamDecoding`.
174	     * Please override this function to do anything needed, e.g.
175	     * free allocated buffers.
176	     */
177	    virtual void onStreamEnd() {}
178	
179	    virtual void sendStopSignal()
180	    {
181	        // Update the finished buffer in decoding to let the GPT model know,
182	        // terminating the async thread.
183	        cudaMemcpyAsync(gpt_->getFinishBuffer(),
184	                        finished,
185	                        sizeof(bool) * output_tensors_->at("output_ids").shape[0]
186	                            * output_tensors_->at("output_ids").shape[1],
187	                        cudaMemcpyHostToDevice,
188	                        stream);
189	        cudaStreamSynchronize(stream);
190	    }
191	
192	    void streamDecoding()
193	    {
194	        int input_len      = input_tensors_->at("input_ids").shape[1];
195	        int max_output_len = output_tensors_->at("output_ids").shape[0];
196	        int batch_size     = output_tensors_->at("output_ids").shape[0];
197	
198	        // initialization
199	        is_generation_done           = false;
200	        prev_step                    = 0;
201	        curr_step                    = input_len;
202	        int*  seqlen_buf_            = new int[batch_size];
203	        bool* decoding_finished_buf_ = new bool[batch_size];
204	        bool* finished               = new bool[batch_size];
205	        std::fill(seqlen_buf_, seqlen_buf_ + batch_size, input_len);
206	        std::fill(decoding_finished_buf_, decoding_finished_buf_ + batch_size, false);
207	        std::fill(finished, finished + batch_size, false);
208	
209	        // start streaming
210	        onStreamBegin(batch_size, input_len);
211	        while (!(is_generation_done || curr_step == max_output_len)) {
212	            cudaMemcpyAsync(seqlen_buf_,
213	                            (int*)output_tensors_->at("sequence_length").data,
214	                            sizeof(int) * batch_size,
215	                            cudaMemcpyDeviceToHost,
216	                            stream);
217	            cudaStreamSynchronize(stream);
218	            curr_step = *std::max_element(seqlen_buf_, seqlen_buf_ + batch_size);
219	            if (prev_step < curr_step) {
220	                int idx_from = prev_step * batch_size;
221	                cudaMemcpyAsync(output_ids + idx_from,
222	                                (int*)(output_tensors_->at("output_ids").data) + idx_from,
223	                                sizeof(int) * (curr_step - prev_step) * batch_size,
224	                                cudaMemcpyDeviceToHost,
225	                                stream);
226	                cudaStreamSynchronize(stream);
227	                is_generation_done = stopCriteria(prev_step, curr_step, output_ids);
228	                streamHook(prev_step, curr_step, output_ids);
229	            }
230	            else {
231	                // The last token isn't accounted in the length of a sequence
232	                // since the end-token is not included in generated  length.
233	                // So when all the sample generation is done, prev_step  and
234	                // curr_step remain the same.
235	                cudaMemcpyAsync(decoding_finished_buf_,
236	                                gpt_->getFinishBuffer(),
237	                                sizeof(bool) * batch_size,
238	                                cudaMemcpyDeviceToHost,
239	                                stream);
240	                cudaStreamSynchronize(stream);
241	                is_generation_done =
242	                    std::all_of(decoding_finished_buf_, decoding_finished_buf_ + batch_size, [](bool b) { return b; });
243	            }
244	
245	#ifndef NDEBUG
246	            if (prev_step < curr_step) {
247	                int batch_size = output_tensors_->at("output_ids").shape[0];
248	                std::cout << "\r[DEBUG] Step " << curr_step
249	                          << " | seqlen: " << strutils::toString(sequence_lengths, batch_size, false)
250	                          << " | output_ids: "
251	                          << strutils::toString(output_ids + (curr_step - 1) * batch_size, batch_size, false)
252	                          << " | h_finished_buf: " << strutils::toString(finished, batch_size, false)
253	                          << " | d_finished_buf: " << strutils::toString(gpt_->getFinishBuffer(), batch_size, true)
254	                          << std::flush;
255	            }
256	#endif
257	            prev_step = curr_step;
258	        }
259	
260	        if (is_generation_done) {
261	            // The EOD token isn't accounted in the sequence length.
262	            // So, we need to copy the last step's output_ids
263	            // (all of them are the end tokens).
264	            int idx_from = curr_step * batch_size;
265	            cudaMemcpyAsync(output_ids + idx_from,
266	                            (int*)(output_tensors_->at(0).data) + idx_from,
267	                            sizeof(int) * batch_size,
268	                            cudaMemcpyDeviceToHost,
269	                            stream);
270	            cudaStreamSynchronize(stream);
271	            curr_step++;
272	
273	            streamHook(prev_step, curr_step, output_ids);
274	            sendStopSignal();
275	        }
276	        onStreamEnd();
277	
278	        delete[] seqlen_buf_;
279	        delete[] decoding_finished_buf_;
280	        delete[] finished;
281	    }
282	
283	public:
284	    GptStreamer(int max_batch_size, int max_output_length):
285	        max_batch_size(max_batch_size), max_output_length(max_output_length)
286	    {
287	        output_ids       = new int[max_output_length * max_batch_size];
288	        sequence_lengths = new int[max_batch_size];
289	        finished         = new bool[max_batch_size];
290	        cudaStreamCreate(&stream);
291	    }
292	
293	    ~GptStreamer()
294	    {
295	        delete[] output_ids;
296	        delete[] sequence_lengths;
297	        delete[] finished;
298	        cudaStreamDestroy(stream);
299	    }
300	
301	    void initialize(ParallelGpt<T>*                                gpt,
302	                    std::unordered_map<std::string, Tensor>*       output_tensors,
303	                    const std::unordered_map<std::string, Tensor>* input_tensors,
304	                    const ParallelGptWeight<T>*                    gpt_weights)
305	    {
306	        gpt_            = gpt;
307	        output_tensors_ = output_tensors;
308	        input_tensors_  = input_tensors;
309	        gpt_weights_    = gpt_weights;
310	
311	        int total_output_tokens = max_output_length * max_batch_size;
312	        std::fill(output_ids, output_ids + total_output_tokens, 0);
313	        std::fill(sequence_lengths, sequence_lengths + max_batch_size, output_tensors_->at("sequence_length").shape[0]);
314	        std::fill(finished, finished + max_batch_size, false);
315	
316	        prev_step          = 0;
317	        curr_step          = 0;
318	        is_generation_done = false;
319	    }
320	
321	    /**
322	     * \brief Forward a model and asynchronously check whether to stop.
323	     *
324	     * The device having the last rank of a pipeline parallel group checks and
325	     * broadcasts to the other devices. So only the last rank runs asynchronously
326	     * and monitor whether to terminate by given stop criteria.
327	     *
328	     * For now, we provide a streaming function as a separated example with
329	     * minimum update of the GPT module.
330	     *
331	     * \param gpt An ParallelGpt pointer to generate tokens.
332	     * \param output_tensors A vector of tensors, containing the output tensors of gpt, including
333	     *                          output_ids, sequence_lengths and cum_log_probs
334	     * \param input_tensors A vector of tensors, containing the input tensors of gpt, including
335	     *                          input_ids, input_lengths and request_output_len
336	     * \param gpt_weights A ParallelGptWeight pointer, which continas the weights of gpt model
337	     */
338	    void run(ParallelGpt<T>*                                gpt,
339	             std::unordered_map<std::string, Tensor>*       output_tensors,
340	             const std::unordered_map<std::string, Tensor>* input_tensors,
341	             const ParallelGptWeight<T>*                    gpt_weights)
342	    {
343	        initialize(gpt, output_tensors, input_tensors, gpt_weights);
344	        // Only the last rank of pipeline parallel will run asynchronously
345	        // and monitor whether to terminate by given stop criteria.
346	        if (gpt_->getPipelineParallelRank() < gpt_->getPipelineParallelSize() - 1) {
347	            gpt_->forward(output_tensors_, input_tensors_, gpt_weights_);
348	            return;
349	        }
350	
351	        int device;
352	        check_cuda_error(cudaGetDevice(&device));
353	        std::async(std::launch::async, [&]() {
354	            check_cuda_error(cudaSetDevice(device));
355	            gpt_->forward(output_tensors_, input_tensors_, gpt_weights_);
356	        });
357	        streamDecoding();
358	    }
359	};
360	
361	template<typename T>
362	class GptFileStreamer: public GptStreamer<T> {
363	
364	protected:
