453	int read_start_ids(int               batch_size,
454	                   std::vector<int>* v_start_lengths,
455	                   std::vector<int>* v_start_ids,
456	                   int&              max_input_len,
457	                   const int         end_id,
458	                   const int         beam_width)
459	{
460	    std::vector<std::vector<int>> tmp_start_ids;
461	    std::vector<int>              tmp_start_lengths;
462	
463	    std::string   file_name = "../examples/cpp/multi_gpu_gpt/start_ids.csv";
464	    std::ifstream start_id_file(file_name, std::ios::in);
465	    if (start_id_file.is_open()) {
466	        std::string line;
467	        int         i0 = 0;
468	        while (std::getline(start_id_file, line)) {
469	            std::stringstream lineStream(line);
470	            std::string       vals;
471	            int               i1 = 0;
472	            std::vector<int>  tmp_vec;
473	            while (std::getline(lineStream, vals, ',')) {
474	                tmp_vec.push_back(std::stoi(vals));
475	                i1++;
476	            }
477	            tmp_start_ids.push_back(tmp_vec);
478	            tmp_start_lengths.push_back(i1);
479	            i0++;
480	        }
481	    }
482	    else {
483	        printf("[WARNING] Cannot open the file '%s'. \n", file_name.c_str());
484	        max_input_len = 0;
485	        return 0;
486	    }
487	
488	    max_input_len = tmp_start_lengths.data()[0];
489	    for (uint i = 1; i < (uint)tmp_start_lengths.size(); i++) {
490	        max_input_len = max_input_len > tmp_start_lengths.data()[i] ? max_input_len : tmp_start_lengths.data()[i];
491	    }
492	
493	    while ((int)tmp_start_lengths.size() < batch_size) {
494	        std::vector<int> padding_ids;
495	        for (int i = 0; i < max_input_len; i++) {
496	            padding_ids.push_back(end_id);
497	        }
498	        tmp_start_ids.push_back(padding_ids);
499	        tmp_start_lengths.push_back(max_input_len);
500	    }
501	
502	    // Add padding
503	    for (int i = 0; i < (int)tmp_start_ids.size(); i++) {
504	        for (int j = (int)tmp_start_ids[i].size(); j < max_input_len; j++) {
505	            tmp_start_ids[i].push_back(end_id);
506	        }
507	    }
508	
509	    for (int i = 0; i < (int)tmp_start_ids.size(); i++) {
510	        for (int b = 0; b < beam_width; b++) {
511	            for (int j = 0; j < (int)tmp_start_ids[i].size(); j++) {
512	                v_start_ids->push_back(tmp_start_ids[i][j]);
513	            }
514	            v_start_lengths->push_back(tmp_start_lengths[i]);
515	        }
516	    }
517	    return 0;
518	}
