520	template<typename T>
521	void multi_gpu_gpt_example(const INIReader reader)
522	{
523	    const std::string model_name         = reader.Get("ft_instance_hyperparameter", "model_name");
524	    const size_t      max_batch_size     = reader.GetInteger("ft_instance_hyperparameter", "max_batch_size");
525	    const size_t      max_seq_len        = reader.GetInteger("ft_instance_hyperparameter", "max_seq_len");
526	    const size_t      beam_width         = reader.GetInteger("ft_instance_hyperparameter", "beam_width");
527	    const uint        top_k              = (uint)reader.GetInteger("ft_instance_hyperparameter", "top_k");
528	    const float       top_p              = reader.GetFloat("ft_instance_hyperparameter", "top_p");
529	    const float       temperature        = reader.GetFloat("ft_instance_hyperparameter", "temperature");
530	    const float       repetition_penalty = reader.GetFloat("ft_instance_hyperparameter", "repetition_penalty");
531	    const std::string model_dir          = std::string(reader.Get("ft_instance_hyperparameter", "model_dir"));
532	    const bool        sparse             = static_cast<bool>(reader.GetInteger("ft_instance_hyperparameter", "sparse"));
533	    const float       len_penalty        = reader.GetFloat("ft_instance_hyperparameter", "len_penalty");
534	    const float       beam_search_diversity_rate =
535	        reader.GetFloat("ft_instance_hyperparameter", "beam_search_diversity_rate");
536	
537	    const int tensor_para_size   = reader.GetInteger("ft_instance_hyperparameter", "tensor_para_size");
538	    const int pipeline_para_size = reader.GetInteger("ft_instance_hyperparameter", "pipeline_para_size");
539	
540	    const int int8_mode = reader.GetInteger("ft_instance_hyperparameter", "int8_mode");
541	
542	    const size_t head_num       = reader.GetInteger(model_name, "head_num");
543	    const size_t size_per_head  = reader.GetInteger(model_name, "size_per_head");
544	    const size_t vocab_size     = reader.GetInteger(model_name, "vocab_size");
545	    const size_t decoder_layers = reader.GetInteger(model_name, "decoder_layers");
546	    const size_t hidden_units   = head_num * size_per_head;
547	    const size_t inter_size     = 4 * hidden_units;
548	
549	    const size_t request_batch_size = reader.GetInteger("request", "request_batch_size");
550	    // The length of tokens we hope this model to generate
551	    const int request_output_len = reader.GetInteger("request", "request_output_len");
552	
553	    const int start_id = 50256;
554	    const int end_id   = 50256;
555	
556	    if (USE_ASYNC) {
557	        FT_CHECK(beam_width == 1);  // async forward does not support beam search
558	    }
559	
560	    FT_CHECK(head_num % tensor_para_size == 0);
561	    FT_CHECK(decoder_layers % pipeline_para_size == 0);
562	
563	    // Prepare the parallelism parameters
564	    int rank       = mpi::getCommWorldRank();
565	    int world_size = mpi::getCommWorldSize();
566	    if (rank == 0) {
567	        printf("Total ranks: %d.\n", world_size);
568	    }
569	    int device, device_count;
570	    check_cuda_error(cudaGetDeviceCount(&device_count));
571	    check_cuda_error(cudaSetDevice(rank % device_count));
572	    check_cuda_error(cudaGetDevice(&device));
573	
574	    struct cudaDeviceProp prop;
575	    check_cuda_error(cudaGetDeviceProperties(&prop, device));
576	    printf("Device %s\n", prop.name);
577	
578	    printf("P%d is running with %d GPU.\n", rank, device);
579	
580	    if (tensor_para_size * pipeline_para_size != world_size) {
581	        printf("[ERROR] tensor_para_size * pipeline_para_size should equal to world_size \n");
582	        exit(-1);
583	    }
584	
585	    const int tensor_para_rank   = rank % tensor_para_size;
586	    const int pipeline_para_rank = rank / tensor_para_size;
587	    const int layers_per_group   = decoder_layers / pipeline_para_size;
588	    if (layers_per_group * pipeline_para_size != (int)decoder_layers) {
589	        printf("[ERROR] layers_per_group (%d) * pipeline_para_size (%d) should equal to decoder_layers (%ld) \n",
590	               layers_per_group,
591	               pipeline_para_size,
592	               decoder_layers);
593	        exit(-1);
594	    }
595	
596	    // assume gpu_num = n * k,
597	    // tensor parallelism group size is n
598	    // pipeline parallelism group size is k
599	
600	    NcclParam tensor_para;
601	    NcclParam pipeline_para;
602	    ftNcclInitialize(tensor_para, pipeline_para, tensor_para_size, pipeline_para_size);
603	
604	    // Read ids of request from file.
605	    int              max_input_len = -1;
606	    std::vector<int> v_start_lengths;
607	    std::vector<int> v_start_ids;
608	    read_start_ids(request_batch_size, &v_start_lengths, &v_start_ids, max_input_len, end_id, beam_width);
609	
610	    int* d_input_ids;
611	    int* d_input_lengths;
612	    if (max_input_len == 0) {
613	        // unconditional case, no input ids, so do nothing.
614	        d_input_ids     = nullptr;
615	        d_input_lengths = nullptr;
616	        max_input_len   = 0;
617	    }
618	    else {
619	        // conditional case.
620	        deviceMalloc(&d_input_ids, request_batch_size * beam_width * max_input_len, false);
621	        deviceMalloc(&d_input_lengths, request_batch_size * beam_width, false);
622	        cudaH2Dcpy(d_input_ids, v_start_ids.data(), request_batch_size * beam_width * max_input_len);
623	        cudaH2Dcpy(d_input_lengths, v_start_lengths.data(), request_batch_size * beam_width);
624	    }
625	
626	    const int total_output_len = max_input_len + request_output_len;
627	    if (total_output_len > (int)max_seq_len) {
628	        printf("[ERROR] total_output_len (%d) should be <= max_seq_len (%ld). \n", total_output_len, max_seq_len);
629	        exit(-1);
630	    }
631	
632	    cudaStream_t     stream;
633	    cublasHandle_t   cublas_handle;
634	    cublasLtHandle_t cublaslt_handle;
635	    cudaStreamCreate(&stream);
636	    cublasCreate(&cublas_handle);
637	    cublasLtCreate(&cublaslt_handle);
638	    cublasSetStream(cublas_handle, stream);
639	    cublasAlgoMap* cublas_algo_map = new cublasAlgoMap("gemm_config.in");
640	
641	    Allocator<AllocatorType::CUDA> allocator(getDevice());
642	
643	    std::mutex*     cublas_wrapper_mutex = new std::mutex();
644	    cublasMMWrapper cublas_wrapper =
645	        cublasMMWrapper(cublas_handle, cublaslt_handle, stream, cublas_algo_map, cublas_wrapper_mutex, &allocator);
646	    if (std::is_same<T, half>::value) {
647	        cublas_wrapper.setGemmConfig(CUDA_R_16F, CUDA_R_16F, CUDA_R_16F, CUDA_R_32F);
648	    }
649	#ifdef ENABLE_BF16
650	    else if (std::is_same<T, __nv_bfloat16>::value) {
651	        cublas_wrapper.setBF16GemmConfig();
652	    }
653	#endif
654	    else if (std::is_same<T, float>::value) {
655	        cublas_wrapper.setFP32GemmConfig();
656	    }
657	
658	    ParallelGptWeight<T> gpt_weights(hidden_units,
659	                                     inter_size,
660	                                     vocab_size,
661	                                     decoder_layers,
662	                                     max_seq_len,
663	                                     tensor_para_size,
664	                                     tensor_para_rank,
665	                                     pipeline_para_size,
666	                                     pipeline_para_rank,
667	                                     int8_mode);
668	    gpt_weights.loadModel(model_dir);
669	
670	    unsigned long long int random_seed = 0;
671	
672	    AttentionType attention_type = getAttentionType<T>(size_per_head,
673	                                                       getSMVersion(),
674	                                                       true,   // remove_padding
675	                                                       0,      // gpt supports any-seq-length fmha
676	                                                       true,   // is_fuse
677	                                                       false,  // with_relative_position_bias
678	                                                       true);  // causal_mask
679	
680	    ParallelGpt<T> gpt = ParallelGpt<T>(0,  // max_batch_size, FT will adjust the buffer automatically.
681	                                        0,  // max_seq_len, FT will adjust the buffer automatically.
682	                                        0,  // max_input_len, FT will adjust the buffer automatically.
683	                                        beam_width,
684	                                        head_num,
685	                                        size_per_head,
686	                                        inter_size,
687	                                        decoder_layers,
688	                                        0,   // expert_num
689	                                        0,   // moe_k
690	                                        {},  // moe_layer_index
691	                                        vocab_size,
692	                                        start_id,
693	                                        end_id,
694	                                        end_id + 1,  // p_prompt_tuning token start id
695	                                        PromptLearningType::no_prompt,
696	                                        gptVariantParams{},
697	                                        0.0f,
698	                                        top_k,
699	                                        top_p,
700	                                        random_seed,
701	                                        temperature,
702	                                        0.0f,  // len_penalty,
703	                                        repetition_penalty,
704	                                        tensor_para,
705	                                        pipeline_para,
706	                                        stream,
707	                                        &cublas_wrapper,
708	                                        &allocator,
709	                                        false,
710	                                        &prop,
711	                                        attention_type,
712	                                        false,
713	                                        int8_mode);
714	
715	    int* d_output_ids;
716	    int* d_sequence_lengths;
717	    deviceMalloc(&d_output_ids, request_batch_size * beam_width * total_output_len, false);
718	    deviceMalloc(&d_sequence_lengths, request_batch_size * beam_width, false);
719	    std::vector<uint32_t> output_seq_len(request_batch_size, total_output_len);
720	
721	    std::unordered_map<std::string, Tensor> input_tensors = std::unordered_map<std::string, Tensor>{
722	        {"input_ids",
723	         Tensor{MEMORY_GPU,
724	                TYPE_INT32,
725	                std::vector<size_t>{request_batch_size * beam_width, (size_t)max_input_len},
726	                d_input_ids}},
727	        {"input_lengths",
728	         Tensor{MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size * beam_width}, d_input_lengths}},
729	        {"output_seq_len",
730	         Tensor{MEMORY_CPU, TYPE_UINT32, std::vector<size_t>{request_batch_size}, output_seq_len.data()}}};
731	    if (top_k == 0 && top_p == 0.0f) {
732	        FT_CHECK(beam_width > 1);
733	        input_tensors.insert({"beam_search_diversity_rate",
734	                              Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &beam_search_diversity_rate}});
735	    }
736	    else {
737	        if (top_p != 0.0f) {
738	            input_tensors.insert({"runtime_top_p", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &top_p}});
739	        }
740	        if (top_k != 0) {
741	            input_tensors.insert({"runtime_top_k", Tensor{MEMORY_CPU, TYPE_UINT32, std::vector<size_t>{1}, &top_k}});
742	        }
743	    }
744	    input_tensors.insert({"temperature", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &temperature}});
745	    input_tensors.insert({"len_penalty", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &len_penalty}});
746	    input_tensors.insert(
747	        {"repetition_penalty", Tensor{MEMORY_CPU, TYPE_FP32, std::vector<size_t>{1}, &repetition_penalty}});
748	    input_tensors.insert({"random_seed", Tensor{MEMORY_CPU, TYPE_UINT64, std::vector<size_t>{1}, &random_seed}});
749	
750	    std::unordered_map<std::string, Tensor> output_tensors = std::unordered_map<std::string, Tensor>{
751	        {"output_ids",
752	         Tensor{MEMORY_GPU,
753	                TYPE_INT32,
754	                std::vector<size_t>{request_batch_size, beam_width, (size_t)total_output_len},
755	                d_output_ids}},
756	        {"sequence_length",
757	         Tensor{MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size, beam_width}, d_sequence_lengths}},
758	        {"output_log_probs",
759	         Tensor{MEMORY_GPU,
760	                TYPE_FP32,
761	                std::vector<size_t>{(size_t)request_output_len, request_batch_size, beam_width},
762	                nullptr}}};
763	
764	    print_mem_usage();
765	
766	    cudaDeviceSynchronize();
767	    mpi::barrier();
768	
769	    int  total_output_ids   = total_output_len * request_batch_size;
770	    int* h_output_ids       = new int[total_output_ids];
771	    int* h_sequence_lengths = new int[request_batch_size * beam_width];
772	
773	    if (rank == 0) {
774	        printf("[INFO] Warming up\n");
775	    }
776	
777	    // initialize output buffers
778	    std::fill(h_output_ids, h_output_ids + total_output_ids, 0);
779	    std::fill(h_sequence_lengths, h_sequence_lengths + request_batch_size, 0);
780	
781	    std::string        stream_file = pipeline_para_rank == (pipeline_para_size - 1) ? "out.stream" : "";
782	    GptFileStreamer<T> gpt_streamer(request_batch_size * beam_width, total_output_len, stream_file);
783	
784	    cudaProfilerStart();
785	    // warm up
786	    ft_nvtx::setScope("warmup_time");
787	    PUSH_RANGE("warmup time")
788	    if (USE_ASYNC) {
789	        gpt_streamer.run(&gpt, &output_tensors, &input_tensors, &gpt_weights);
790	    }
791	    else {
792	        gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
793	    }
794	    cudaDeviceSynchronize();
795	    mpi::barrier();
796	    POP_RANGE;
797	    ft_nvtx::resetScope();
798	
799	    if (rank == 0) {
800	        printf("[INFO] Profiling\n");
801	    }
802	    // reset output buffers
803	    std::fill(h_output_ids, h_output_ids + total_output_ids, 0);
804	    std::fill(h_sequence_lengths, h_sequence_lengths + request_batch_size, 0);
805	    deviceFill(d_sequence_lengths, request_batch_size, 0);
806	
807	    struct timeval start, end;
808	    cudaDeviceSynchronize();
809	    mpi::barrier();
810	    gettimeofday(&start, NULL);
811	
812	    ft_nvtx::setScope("total_time");
813	    PUSH_RANGE("total time")
814	    int ite = 1;
815	    for (int i = 0; i < ite; ++i) {
816	        if (USE_ASYNC) {
817	            gpt_streamer.run(&gpt, &output_tensors, &input_tensors, &gpt_weights);
818	        }
819	        else {
820	            gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
821	        }
822	    }
823	
824	    cudaDeviceSynchronize();
825	    mpi::barrier();
826	    POP_RANGE;
827	    ft_nvtx::resetScope();
828	    gettimeofday(&end, NULL);
829	
830	    cudaProfilerStop();
831	
832	    if (rank == 0) {
833	        printf("[INFO] request_batch_size %ld beam_width %ld head_num %ld size_per_head %ld total_output_len %d"
834	               " decoder_layers %ld vocab_size %ld FT-CPP-decoding-beamsearch-time %.2f ms\n",
835	               request_batch_size,
836	               beam_width,
837	               head_num,
838	               size_per_head,
839	               total_output_len,
840	               decoder_layers,
841	               vocab_size,
842	               ((end.tv_sec - start.tv_sec) * 1000 + (end.tv_usec - start.tv_usec) * 0.001) / ite);
843	
844	        std::string fName   = USE_ASYNC ? "out.async" : "out.sync";
845	        auto        outFile = std::ofstream(fName, std::ios::out);
846	        if (!outFile.is_open()) {
847	            printf("[WARNING] Cannot write results into output file %s \n", fName.c_str());
848	        }
849	        else {
850	            size_t outCount = total_output_len * request_batch_size;
851	            int*   hBuf     = new int[outCount];
852	            cudaDeviceSynchronize();
853	            cudaMemcpyAsync(hBuf, d_output_ids, outCount * sizeof(int), cudaMemcpyDeviceToHost, stream);
854	            cudaDeviceSynchronize();
855	
856	            {
857	                std::cout << "Writing " << outCount << " elements\n";
858	                int zeroCount = 0;
859	                for (size_t i = 0; i < outCount; i++) {
860	                    if (hBuf[i] == int(0)) {
861	                        zeroCount++;
862	                    }
863	                    outFile << hBuf[i];
864	                    if ((i + 1) % (total_output_len) == 0) {
865	                        outFile << std::endl;
866	                    }
867	                    else {
868	                        outFile << " ";
869	                    }
870	
871	                    if (i < 10) {
872	                        printf("%5d ", hBuf[i]);
873	                    }
874	                    if ((i + 1) % (total_output_len) == 0 && i < 10) {
875	                        std::cout << std::endl;
876	                    }
877	                }
878	                std::cout << std::endl << "zeroCount = " << zeroCount << std::endl;
879	            }
880	            delete[] hBuf;
881	        }
882	    }
883	
884	    ftNcclParamDestroy(tensor_para);
885	    ftNcclParamDestroy(pipeline_para);
886	
887	    delete[] h_output_ids;
888	    delete[] h_sequence_lengths;
889	    return;
890	}
