654	        bool masked     = (seq_idx >= batch_size);
655	        bool first_iter = seq_idx < blockDim.x;
656	
657	        int is_first_occur = masked ? 0 : shared_contexts[seq_idx] == seq_idx;
658	        BlockScan(temp_storage).ExclusiveSum(is_first_occur, scan);
659	
660	        if (!masked && is_first_occur) {
661	            int compact_idx = scan + (first_iter ? 0 : scan_offset);
662	            // Context rep. writes initial index
663	            batch_to_compact[seq_idx * beam_width] = compact_idx;
664	            // input ids are tiled in context part
665	            compact_to_batch[compact_idx] = seq_idx * beam_width;
666	        }
667	
668	        __syncthreads();
669	
670	        if (threadIdx.x == blockDim.x - 1) {
671	            scan_offset = scan + is_first_occur + (first_iter ? 0 : scan_offset);
672	        }
673	
674	        __syncthreads();
675	
676	        if (!masked && !is_first_occur) {
677	            // Fill the rest of batch_to_compact based on what rep. wrote
678	            const int src_idx                      = batch_to_compact[shared_contexts[seq_idx] * beam_width];
679	            batch_to_compact[seq_idx * beam_width] = src_idx;
680	        }
681	
682	        if (!masked) {
683	            // set same compact idx for beams
684	            for (int beam_id = 1; beam_id < beam_width; ++beam_id) {
685	                batch_to_compact[seq_idx * beam_width + beam_id] = batch_to_compact[seq_idx * beam_width];
686	            }
687	        }
688	    }
689	
690	    if (threadIdx.x == 0) {
691	        *compact_size = scan_offset;
692	    }
693	}
