877	template<typename T>
878	__global__ void uncompact_caches(T*         uncompact_k_cache,
879	                                 T*         uncompact_v_cache,
880	                                 const T*   compact_k_cache,
881	                                 const T*   compact_v_cache,
882	                                 const int* batch_to_compact_idx,
883	                                 size_t     batch_size,
884	                                 size_t     num_heads,
885	                                 size_t     max_seq_len,
886	                                 size_t     seq_len,
887	                                 size_t     size_per_head,
888	                                 size_t     local_batch_size,
889	                                 size_t     ite)
890	{
891	    const int hidden_dimension    = num_heads * size_per_head;
892	    const int num_elems_per_batch = seq_len * hidden_dimension;
893	    const int num_elems_cache     = batch_size * num_elems_per_batch;
894	    const int x_size              = 16 / sizeof(T);
895	
896	    for (int global_idx = blockIdx.x * blockDim.x + threadIdx.x; global_idx < 2 * num_elems_cache;
897	         global_idx += blockDim.x * gridDim.x) {
898	
899	        const bool     handle_k  = global_idx < num_elems_cache;
900	        const T* const cache_src = handle_k ? compact_k_cache : compact_v_cache;
901	        T* const       cache_dst = handle_k ? uncompact_k_cache : uncompact_v_cache;
902	        const int      idx       = handle_k ? global_idx : global_idx - num_elems_cache;
903	
904	        const int src_offset = idx % num_elems_per_batch;
905	        const int batch_idx  = idx / num_elems_per_batch;
906	        const int batch_src  = batch_to_compact_idx[batch_idx] - ite * local_batch_size;
907	
908	        if (batch_src < 0 || batch_src >= local_batch_size) {
909	            continue;
910	        }
911	
912	        int dst_offset;
913	        if (handle_k) {
914	            const int i0 = idx % (x_size * seq_len);
915	            const int i1 = (idx / (x_size * seq_len)) % (num_heads * size_per_head / x_size);
916	            dst_offset   = i1 * max_seq_len * x_size + i0;
917	        }
918	        else {
919	            const int i0 = idx % (size_per_head * seq_len);
920	            const int i1 = (idx / (size_per_head * seq_len)) % (num_heads);
921	            dst_offset   = i1 * max_seq_len * size_per_head + i0;
922	        }
923	
924	        cache_dst[batch_idx * max_seq_len * hidden_dimension + dst_offset] =
925	            cache_src[batch_src * num_elems_per_batch + src_offset];
926	    }
927	}
